class e{constructor(){this.options={root:null,rootMargin:"0px 0px -100px 0px",threshold:.1},this.init()}init(){this.observer=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&e.target.classList.add("is-visible")})},this.options),this.observeElements()}observeElements(){document.querySelectorAll("[data-animate]").forEach(e=>this.observer.observe(e))}}document.addEventListener("DOMContentLoaded",()=>{new e});export{e as default};
